class ListNode {
    constructor(val, next = null) {
        this.val = val;
        this.next = next;
    }
}

function reorderList(head) {
    if (!head || !head.next || !head.next.next) return;

    // Find the middle node
    let slow = head;
    let fast = head;
    while (fast.next && fast.next.next) {
        slow = slow.next;
        fast = fast.next.next;
    }

    // Reverse the second half
    let prev = null;
    let curr = slow.next;
    let next;
    while (curr) {
        next = curr.next;
        curr.next = prev;
        prev = curr;
        curr = next;
    }
    slow.next = null;

    // Merge two halves
    let first = head;
    let second = prev;
    while (second) {
        next = first.next;
        first.next = second;
        first = second;
        second = next;
    }
}
```

    1. Find the middle of the linked list using the slow and fast pointer technique.
2. Reverse the second half of the linked list by iterating through it, and changing each node's next pointer to the previous node.
3. Merge the two halves of the list by alternating nodes from the first and second halves.

